test.describe('Admin Inventory Management', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/admin/inventory.html', { waitUntil: 'domcontentloaded' });
  });

  test('should load inventory page without critical errors', async ({ page }) => {
    await expect(page).toHaveURL(/.*inventory\.html/);

    // Check for basic page structure
    await expect(page.locator('body')).toBeVisible();
  });

  test('should have inventory management UI elements', async ({ page }) => {
    // Check for common inventory UI patterns
    const hasTable = page.locator('table').count() > 0;
    const hasCards = page.locator('[class*="card"]').count() > 0;

    // Should have at least one of these
    const hasUI = (await hasTable) || (await hasCards);
    expect(hasUI).toBeTruthy();
  });
});

