/**
 * Integration Tests — Cross-page Navigation
 */
test.describe('Navigation Integration Tests', () => {
  test('should navigate from admin dashboard to other admin pages', async ({ page }) => {
    await page.goto('/admin/dashboard.html', { waitUntil: 'domcontentloaded' });

    // Check for navigation links
    const navLinks = page.locator('a[href*="admin/"]');
    const count = await navLinks.count();

    // Dashboard should have navigation to other admin pages
    expect(count).toBeGreaterThan(0);
  });

  test('should have consistent header across admin pages', async ({ page }) => {
    await page.goto('/admin/dashboard.html', { waitUntil: 'domcontentloaded' });
    const header1 = await page.locator('header, [class*="header"], nav').count();

    await page.goto('/admin/campaigns.html', { waitUntil: 'domcontentloaded' });
    const header2 = await page.locator('header, [class*="header"], nav').count();

    // Both pages should have header elements
    expect(header1).toBeGreaterThan(0);
    expect(header2).toBeGreaterThan(0);
  });
});

/**
 * Accessibility Tests — Basic Checks
 */
test.describe('Accessibility Tests — Admin Pages', () => {
  const adminPages = [
    '/admin/inventory.html',
    '/admin/loyalty.html',
    '/admin/menu.html',
    '/admin/notifications.html',
  ];

  for (const pagePath of adminPages) {
    test(`${pagePath} should have accessible forms`, async ({ page }) => {
      await page.goto(pagePath, { waitUntil: 'domcontentloaded' });

      // Check that inputs have associated labels or aria-labels
      const inputs = page.locator('input:not([type="hidden"]), textarea, select');
      const count = await inputs.count();

      for (let i = 0; i < Math.min(count, 5); i++) {
        const input = inputs.nth(i);
        const hasLabel = await input.evaluate(el => {
          // Check for aria-label
          if (el.getAttribute('aria-label')) return true;
          // Check for id and associated label
          const id = el.id;
          if (id && document.querySelector(`label[for="${id}"]`)) return true;
          // Check for parent label
          return el.closest('label') !== null;
        });

        // Not all inputs need labels (some might be buttons, etc.)
        // This is a soft check - just log if missing
        if (!hasLabel) {
          console.log(`Input at index ${i} in ${pagePath} may be missing label`);
        }
      }
    });
  }
});
